#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X; scanf("%d", &X);
        int km = X > 300 ? X : 300;
        printf("%d\n", km * 10);
    }
    return 0;
}

